import React, { useMemo, useState } from 'react';
import { Button, Input, Modal, addToast } from '@linm-soft/common-components';
import { useAppDispatch } from '../../../store/hooks';
import { masterService } from '../../../services/master/masterService';
import type { ToolsEquipmentDto } from '../../../services/master/models';
import { normalizeCode } from '../../../utils/codeField';
import { scrollToFirstFieldError } from '../../../utils/catalogFormValidation';
import {CatalogFormFooter, CatalogListPagination, useCatalogListPaging, CatalogCompanyTh, CatalogCompanyTd} from '../../../components/catalog';

import styles from '../../../styles/erpPage.module.css';

const TEST_ID = 'dm-ccdc';

type FormErrors = Partial<Record<'code' | 'name', string>>;

const CcdcPage: React.FC = () => {
  const dispatch = useAppDispatch();
  const [searchDraft, setSearchDraft] = useState('');
  const [search, setSearch] = useState('');
  const [items, setItems] = useState<ToolsEquipmentDto[]>([]);
  const sessionCompanyName = useMemo(() => items[0]?.companyName, [items]);
  const [totalCount, setTotalCount] = useState(0);
  const [loading, setLoading] = useState(false);
  const [modalOpen, setModalOpen] = useState(false);
  const [editing, setEditing] = useState<ToolsEquipmentDto | null>(null);
  const [form, setForm] = useState<Partial<ToolsEquipmentDto>>({ isActive: true });
  const [errors, setErrors] = useState<FormErrors>({});
  const [saving, setSaving] = useState(false);
  const [deleteId, setDeleteId] = useState<string | null>(null);
  const [reloadKey, setReloadKey] = useState(0);

  const { page, setPage, pageSize, setPageSize, resetPage } = useCatalogListPaging();

  const handleSearch = () => {
    setSearch(searchDraft.trim());
    resetPage();
  };
  const refresh = () => setReloadKey(k => k + 1);

  React.useEffect(() => {
    let cancelled = false;
    setLoading(true);
    const t = setTimeout(() => {
      masterService
        .getToolsEquipment({ search: search.trim() || undefined, page, pageSize })
        .then(data => {
          if (!cancelled) {
            setItems(data.items);
            setTotalCount(data.totalCount);
          }
        })
        .catch(err => {
          if (!cancelled) dispatch(addToast({ message: err?.message ?? 'Lỗi tải CCDC', type: 'error' }));
        })
        .finally(() => { if (!cancelled) setLoading(false); });
    }, 0);
    return () => { cancelled = true; clearTimeout(t); };
  }, [search, page, pageSize, reloadKey, dispatch]);

  const clearFieldError = (key: keyof FormErrors) => {
    setErrors(prev => {
      if (!prev[key]) return prev;
      const next = { ...prev };
      delete next[key];
      return next;
    });
  };

  const validate = (): FormErrors => {
    const next: FormErrors = {};
    if (!form.code?.trim()) next.code = 'Nhập mã CCDC';
    if (!form.name?.trim()) next.name = 'Nhập tên CCDC';
    return next;
  };

  const openAdd = () => {
    setEditing(null);
    setForm({ isActive: true });
    setErrors({});
    setModalOpen(true);
  };

  const openEdit = (row: ToolsEquipmentDto) => {
    setEditing(row);
    setForm({ ...row });
    setErrors({});
    setModalOpen(true);
  };

  const handleSave = async () => {
    const nextErrors = validate();
    if (Object.keys(nextErrors).length > 0) {
      setErrors(nextErrors);
      scrollToFirstFieldError(TEST_ID);
      return;
    }
    setSaving(true);
    try {
      if (editing) await masterService.updateToolsEquipment(editing.id, form);
      else await masterService.createToolsEquipment(form);
      dispatch(addToast({
        message: editing ? 'Cập nhật CCDC thành công' : 'Tạo CCDC thành công',
        type: 'success',
      }));
      setModalOpen(false);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Lưu thất bại', type: 'error' }));
    } finally {
      setSaving(false);
    }
  };

  const handleDelete = async (id: string) => {
    try {
      await masterService.deleteToolsEquipment(id);
      dispatch(addToast({ message: 'Xóa CCDC thành công', type: 'success' }));
      setDeleteId(null);
      setReloadKey(k => k + 1);
    } catch (err: unknown) {
      dispatch(addToast({ message: err instanceof Error ? err.message : 'Xóa thất bại', type: 'error' }));
    }
  };

  return (
    <div className={styles.page}>
      <div className={styles.pageHeader}>
        <div className={styles.titleBlock}>
          <h1 className={styles.title}><i className="fas fa-toolbox" /> Danh mục CCDC</h1>
        </div>
        <div className={styles.headerActions}>
          <Button variant="primary" onClick={openAdd} data-testid={`${TEST_ID}-add-btn`}>
            <i className="fas fa-plus" /> Thêm CCDC
          </Button>
        </div>
      </div>

      <div className={styles.filtersBar} data-testid={`${TEST_ID}-filters`}>
        <div className={styles.field} data-testid={`${TEST_ID}-field-search`}>
          <Input
            placeholder="Tìm mã, tên..."
            value={searchDraft}
            onChange={e => setSearchDraft(e.target.value)}
            onKeyDown={e => { if (e.key === 'Enter') handleSearch(); }}
          />
        </div>
        <Button
          variant="secondary"
          onClick={handleSearch}
          aria-label="Tìm kiếm"
          data-testid={`${TEST_ID}-search-btn`}
        >
          <i className="fas fa-search" />
        </Button>
        <Button
          variant="secondary"
          onClick={refresh}
          aria-label="Làm mới"
          data-testid={`${TEST_ID}-refresh-btn`}
        >
          <i className="fas fa-sync" />
        </Button>
      </div>

      <div className={styles.tableCard}>
        {loading ? (
          <div className={styles.loading}><i className="fas fa-spinner fa-spin" /> Đang tải...</div>
        ) : items.length === 0 ? (
          <div className={styles.empty}>
            <i className="fas fa-inbox" />
            <p>{search.trim() ? 'Không tìm thấy CCDC phù hợp' : 'Không có dữ liệu'}</p>
          </div>
        ) : (
          <div className={styles.tableWrapper}>
            <table className={styles.table}>
              <thead>
                <tr>
                  <th>Mã</th>
                  <th>Tên</th>
                  <CatalogCompanyTh />
                  <th>ĐVT</th>
                  <th>Tháng PB</th>
                  <th>TT</th>
                  <th className={styles.colActions} />
                </tr>
              </thead>
              <tbody>
                {items.map(r => (
                  <tr key={r.id}>
                    <td><code>{r.code}</code></td>
                    <td>{r.name}</td>
                    <CatalogCompanyTd label={r.companyName} />
                    <td>{r.unit ?? '—'}</td>
                    <td>{r.allocationMonths ?? '—'}</td>
                    <td>
                      <span className={r.isActive ? styles.tagSuccess : styles.tagDefault}>
                        {r.isActive ? 'Dùng' : 'Ngưng'}
                      </span>
                    </td>
                    <td className={styles.colActions}>
                      <button type="button" className={styles.actionBtn} onClick={() => openEdit(r)} title="Sửa">
                        <i className="fas fa-edit" />
                      </button>
                      <button type="button" className={`${styles.actionBtn} ${styles.actionBtnDanger}`} onClick={() => setDeleteId(r.id)} title="Xóa">
                        <i className="fas fa-trash" />
                      </button>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        )}
        {!loading && (
          <CatalogListPagination
            testIdPrefix={TEST_ID}
            page={page}
            totalCount={totalCount}
            pageSize={pageSize}
            onPageChange={setPage}
            onPageSizeChange={setPageSize}
          />
        )}
      </div>

      <Modal isOpen={modalOpen} onClose={() => setModalOpen(false)} title={editing ? 'Sửa CCDC' : 'Thêm CCDC'}>
        <div className={styles.modalBody} data-testid={`${TEST_ID}-form`}>
          <div className={styles.formGrid}>
            <div className={styles.masterCodeNameRow}>
              <div className={styles.field} data-testid={`${TEST_ID}-field-code`}>
                <label className={styles.label}>Mã CCDC *</label>
                <Input
                  value={form.code ?? ''}
                  disabled={!!editing}
                  error={errors.code}
                  className={styles.codeInput}
                  onChange={e => {
                    clearFieldError('code');
                    setForm(f => ({ ...f, code: normalizeCode(e.target.value) }));
                  }}
                />
              </div>
              <div className={styles.field} data-testid={`${TEST_ID}-field-name`}>
                <label className={styles.label}>Tên *</label>
                <Input
                  value={form.name ?? ''}
                  error={errors.name}
                  onChange={e => {
                    clearFieldError('name');
                    setForm(f => ({ ...f, name: e.target.value }));
                  }}
                />
              </div>
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-unit`}>
              <label className={styles.label}>ĐVT</label>
              <Input value={form.unit ?? ''} onChange={e => setForm(f => ({ ...f, unit: e.target.value }))} />
            </div>
            <div className={styles.field} data-testid={`${TEST_ID}-field-allocationMonths`}>
              <label className={styles.label}>Số tháng phân bổ</label>
              <Input
                type="number"
                value={form.allocationMonths ?? ''}
                onChange={e => setForm(f => ({ ...f, allocationMonths: e.target.value ? Number(e.target.value) : undefined }))}
              />
            </div>
          </div>
          <CatalogFormFooter
            companyName={editing?.companyName ?? sessionCompanyName}
            testIdPrefix={TEST_ID}
            checked={form.isActive ?? true}
            onActiveChange={c => setForm(f => ({ ...f, isActive: c }))}
            onCancel={() => setModalOpen(false)}
            onSave={handleSave}
            saving={saving}
          />
        </div>
      </Modal>

      <Modal isOpen={deleteId != null} onClose={() => setDeleteId(null)} title="Xác nhận xóa">
        <p>Bạn có chắc muốn xóa CCDC này?</p>
        <div className={styles.modalActions}>
          <Button variant="secondary" onClick={() => setDeleteId(null)}>Hủy</Button>
          <Button variant="primary" onClick={() => deleteId != null && handleDelete(deleteId)}>Xóa</Button>
        </div>
      </Modal>
    </div>
  );
};

export default CcdcPage;
